const express = require('express');
const session = require('express-session');
const bodyParser = require('body-parser');
const twilio = require('twilio');

const app = express();
const port = 3000;

// Twilio configuration
const accountSid = 'your_account_sid';
const authToken = 'your_auth_token';
const twilioClient = twilio(accountSid, authToken);
const twilioPhoneNumber = 'your_twilio_phone_number';

// Middleware
app.use(bodyParser.urlencoded({ extended: true }));
app.use(session({
  secret: 'your_secret_key',
  resave: false,
  saveUninitialized: true,
  cookie: { secure: false } // Set to true if using HTTPS
}));

// Generate random 6-digit code
function generateCode() {
  return Math.floor(100000 + Math.random() * 900000).toString();
}

// Send SMS
function sendSMS(to, code) {
  return twilioClient.messages.create({
    body: `Your verification code is: ${code}`,
    from: twilioPhoneNumber,
    to: to
  });
}

// Routes
app.get('/send-code', (req, res) => {
  const phoneNumber = req.query.phoneNumber;
  if (!phoneNumber) {
    return res.status(400).send('Phone number is required');
  }

  const code = generateCode();
  req.session.verificationCode = code;

  sendSMS(phoneNumber, code)
    .then(() => res.send('Verification code sent'))
    .catch(err => res.status(500).send('Failed to send SMS'));
});

app.post('/verify-code', (req, res) => {
  const { code } = req.body;
  if (req.session.verificationCode && req.session.verificationCode === code) {
    req.session.verificationCode = null; // Clear code after successful verification
    res.send('Verification successful');
  } else {
    res.status(400).send('Invalid verification code');
  }
});

app.listen(port, () => {
  console.log(`Server running on http://localhost:${port}`);
});